payload.raw:
{
  "layout": "cards-split",
  "title": "创新基础与技术挑战",
  "subtitle": "",
  "cards": [
    {
      "heading": "跨学科全链条团队",
      "body": "核心成员来自哈工大，专业覆盖材料科学、人工智能、算法与系统工程，具备从感知、算法到交互、系统的全链条研发能力。"
    },
    {
      "heading": "深厚科研与技术积淀",
      "body": "累计发表核心期刊论文50余篇，获授权国家发明专利10余项，核心技术经鉴定达国际先进水平，主持多项国家级课题。"
    },
    {
      "heading": "柔性传感器技术瓶颈",
      "body": "当前柔性传感器存在迟滞误差高（>15%）、环境稳定性弱、制备成本高昂以及多源数据长期漂移校准难等核心问题。"
    },
    {
      "heading": "手势识别与交互挑战",
      "body": "深度学习模型在连续手势流、个体差异及环境干扰下鲁棒性下降，复杂工况下精度不足92%、延迟超80ms，且缺乏闭环交互设计。"
    }
  ]
}

