payload.raw:
{
  "layout": "cards-4",
  "title": "创新设计：四大研究方向",
  "subtitle": "",
  "cards": [
    {
      "icon": "terminal",
      "heading": "柔性传感材料",
      "body": "基于仿水膜-鱼网结构的液态金属基导电薄膜与低迟滞聚氨酯介质复合材料，实现高灵敏度（应变系数>150）与低迟滞特性。"
    },
    {
      "icon": "settings",
      "heading": "混合传感架构",
      "body": "融合光纤传感与惯性测量单元（IMU），构建混合传感架构，实现0.1mm级空间分辨率与高鲁棒性。"
    },
    {
      "icon": "search",
      "heading": "手势识别算法",
      "body": "开发分层CNN-LSTM融合架构结合自适应滑动窗口分割，在复杂工况下实现>98.2%的识别准确率与毫秒级实时推理。"
    },
    {
      "icon": "money",
      "heading": "多模态交互系统",
      "body": "集成多模态交互协议栈，嵌入压力/温度动态反馈执行单元，构建感知-意图-反馈闭环，支持跨引擎/设备快速部署。"
    }
  ]
}

